// Webhook v1.1 wraps data: $json.body = request body
const raw = $input.first().json;
const body = raw.body !== undefined ? raw.body : raw;

const failures = Array.isArray(body.failures) ? body.failures : [];
const statuses = body.statuses || {};
const timestamp = new Date().toISOString();

const summary = failures.length > 0
  ? `ALERT: ${failures.length} service(s) DOWN: ${failures.join(', ')}`
  : 'All services healthy';

const allStatuses = Object.entries(statuses)
  .map(([k,v]) => `${v === 'ok' ? 'OK' : 'DOWN'} ${k}: ${v}`)
  .join('\n');

return [{
  json: {
    summary,
    failures,
    statuses,
    all_statuses_text: allStatuses || 'No status data',
    timestamp,
    failure_count: failures.length,
    has_failures: failures.length > 0,
    importance: failures.length > 0 ? 9 : 2
  }
}];
